// ============================================================
// TYPES
// ============================================================

interface TriviaQuestion {
	category: number;
	difficulty: 'easy' | 'medium' | 'hard';
	question: string;
	answers: [string, string, string, string];
	correct: number;
	hint: string;
}

interface GameStats {
	gamesPlayed: number;
	totalScore: number;
	bestScore: number;
	correctAnswers: number;
	totalAnswers: number;
	bestStreak: number;
	lifelinesUsed: number;
	dailyStreak: number;
	lastDailyDate: string;
	level: number;
	xp: number;
	categoryGames: number[];
}

interface LeaderboardEntry {
	name: string;
	score: number;
	mode: string;
	date: string;
}

interface AchDef {
	name: string;
	desc: string;
	check: (s: GameStats, g: GameState) => boolean;
}

type GameMode = 'classic' | 'speed' | 'streak' | 'category' | 'daily' | 'blitz' | 'marathon' | 'practice';
type Difficulty = 'easy' | 'medium' | 'hard';
type Screen = 'title' | 'modeselect' | 'catpick' | 'difficulty' | 'countdown' | 'playing' | 'pause' | 'gameover' | 'achvlist' | 'stats' | 'settings' | 'leaderboard' | 'help';

interface GameState {
	mode: GameMode;
	difficulty: Difficulty;
	category: number;
	questions: TriviaQuestion[];
	currentIndex: number;
	score: number;
	correctCount: number;
	totalAnswered: number;
	combo: number;
	bestCombo: number;
	streak: number;
	bestStreak: number;
	lifelines: { fifty: boolean; skip: boolean; hint: boolean };
	timer: number;
	maxTimer: number;
	eliminated: number[];
	gameStartTime: number;
	elapsedTime: number;
	xpGained: number;
}

