		tm?.setProperties({ content: `${Math.ceil(speedModeTimer)}s` });
	} else if (gs.mode === 'practice' || gs.mode === 'streak') {
		tm?.setProperties({ content: '--' });
	} else {
		tm?.setProperties({ content: `${Math.ceil(gs.timer)}s` });
	}

