	(d.getElementById('lbl-correct') as UIKit.Text)?.setProperties({ content: `Correct: ${gs.correctCount}/${gs.totalAnswered}` });
	(d.getElementById('lbl-accuracy') as UIKit.Text)?.setProperties({ content: `Accuracy: ${accuracy}%` });
	(d.getElementById('lbl-streak') as UIKit.Text)?.setProperties({ content: `Best Streak: ${gs.bestStreak}` });
	(d.getElementById('lbl-combo') as UIKit.Text)?.setProperties({ content: `Best Combo: x${gs.bestCombo}` });
	(d.getElementById('lbl-time') as UIKit.Text)?.setProperties({ content: `Time: ${Math.floor(gs.elapsedTime)}s` });
	(d.getElementById('lbl-xp') as UIKit.Text)?.setProperties({ content: `+${gs.xpGained} XP` });
}

function updateAchievementsUI(): void {
	const d = docs['achvlist'];
	if (!d) return;
	const unlocked = unlockedAchievements.filter(Boolean).length;
	(d.getElementById('lbl-count') as UIKit.Text)?.setProperties({ content: `${unlocked}/40 unlocked` });

	const pageSize = 15;
	const startIdx = achvPage * pageSize;
	const totalPages = Math.ceil(ACHIEVEMENT_DEFS.length / pageSize);

	for (let i = 0; i < pageSize; i++) {
		const achIdx = startIdx + i;
		const el = d.getElementById(`ach${i}`) as UIKit.Text;
		if (!el) continue;
		if (achIdx < ACHIEVEMENT_DEFS.length) {
			const ach = ACHIEVEMENT_DEFS[achIdx];
			const icon = unlockedAchievements[achIdx] ? '[*]' : '[ ]';
			el.setProperties({ content: `${icon} ${ach.name} - ${ach.desc}` });
		} else {
			el.setProperties({ content: '' });
		}
	}

	(d.getElementById('lbl-page') as UIKit.Text)?.setProperties({ content: `${achvPage + 1}/${totalPages}` });
}

